package com.example.mpos.customer;
import android.os.Bundle;import android.widget.*;import androidx.appcompat.app.AppCompatActivity;import com.example.mpos.R;import com.example.mpos.dao.CustomerDao;import com.example.mpos.database.DatabaseHelper;import com.example.mpos.model.Customer;
public class CustomerFormActivity extends AppCompatActivity{CustomerDao dao;Customer c;EditText n,p,e,a;public void onCreate(Bundle b){super.onCreate(b);setContentView(R.layout.activity_customer_form);dao=new CustomerDao(new DatabaseHelper(this));n=findViewById(R.id.inputCustomerName);p=findViewById(R.id.inputCustomerPhone);e=findViewById(R.id.inputCustomerEmail);a=findViewById(R.id.inputCustomerAddress);long id=getIntent().getLongExtra("customer_id",-1);c=id>0?dao.findById(id):new Customer();if(c==null)c=new Customer();n.setText(c.fullName);p.setText(c.phone);e.setText(c.email);a.setText(c.address);findViewById(R.id.btnBack).setOnClickListener(v->finish());findViewById(R.id.btnSaveCustomer).setOnClickListener(v->{if(p.getText().toString().trim().isEmpty()){Toast.makeText(this,"Số điện thoại là bắt buộc",Toast.LENGTH_SHORT).show();return;}c.fullName=n.getText().toString();c.phone=p.getText().toString();c.email=e.getText().toString();c.address=a.getText().toString();try{dao.save(c);finish();}catch(Exception x){Toast.makeText(this,"Số điện thoại đã tồn tại",Toast.LENGTH_SHORT).show();}});}}
